// Configuration
const staticData = this.getWorkflowStaticData('global');
staticData.clients = {}; // Clear previous run data

const CONFIG = {
  rootFolderId: "1iEbSMlsHPX6Sg3y0J0znlT47ri78hk9_",
  spreadsheetId: "1cgctBCQVmqpfQKdomYLfGAWVwRjT1Qw0-dl9F5RzoOg",
  sheetGid: 1199154574,
  sheetName: "Tabelle1",
  openaiModel: "gpt-4o",
  testClientIds: ["1614978","443974","443074","444571","441882","448515","190716","431306"]
};

return [{ json: CONFIG }];

const config = $('Set Config').first().json;
const response = $input.first().json;
const folders = response.files || [];

const allowed = config.testClientIds;
const filtered = folders.filter(f =>
  allowed.includes(f.name) && !f.name.endsWith('_DONE')
);

if (filtered.length === 0) {
  return [{ json: { empty: true, message: 'No client folders to process' } }];
}

return filtered.map(f => ({
  json: {
    clientFolderId: f.id,
    clientFolderName: f.name,
    config: config
  }
}));

const response = $input.first().json;
const prev = $('Split Clients').first().json;
const allFiles = response.files || [];

const allowed = ['.heic', '.jpg', '.jpeg', '.png'];
const mediaFiles = allFiles.filter(f =>
  !f.name.includes('_DONE') &&
  allowed.some(ext => f.name.toLowerCase().endsWith(ext))
);

if (mediaFiles.length === 0) {
  return [{ json: { hasFiles: false, clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName } }];
}

return mediaFiles.map(f => ({
  json: {
    fileId: f.id,
    fileName: f.name,
    mimeType: f.mimeType,
    thumbnailLink: f.thumbnailLink || null,
    clientFolderId: prev.clientFolderId,
    clientFolderName: prev.clientFolderName,
    hasFiles: true
  }
}));

const fileData = $input.first().json;
const prev = $('Split Files').first().json;
const config = $('Set Config').first().json;

let base64Image = null;
let mediaType = 'image/jpeg';

// Try thumbnailLink first (works for HEIC)
const thumbnailLink = fileData.thumbnailLink;
if (thumbnailLink) {
  const highResUrl = thumbnailLink.replace(/=s\d+$/, '=s2048');
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: highResUrl,
      encoding: 'arraybuffer',
    });
    base64Image = Buffer.from(response).toString('base64');
  } catch (e) {
    // thumbnailLink failed
  }
}

// Fallback: direct download for JPG/PNG
if (!base64Image && !fileData.name.toLowerCase().endsWith('.heic')) {
  try {
    const response = await this.helpers.httpRequestWithAuthentication.call(
      this, 'googleDriveOAuth2Api',
      {
        method: 'GET',
        url: `https://www.googleapis.com/drive/v3/files/${fileData.id}?alt=media`,
        encoding: 'arraybuffer',
      }
    );
    base64Image = Buffer.from(response).toString('base64');
    const ext = fileData.name.toLowerCase();
    if (ext.endsWith('.png')) mediaType = 'image/png';
  } catch (e) {}
}

if (!base64Image) {
  return [{ json: {
    error: true,
    errorMessage: 'Could not download image',
    fileName: fileData.name,
    fileId: fileData.id,
    clientFolderId: prev.clientFolderId,
    clientFolderName: prev.clientFolderName
  }}];
}

const PROMPT = `This is a photo of a German hospital monitor screen showing a patient medical report (BIA/body composition analysis). Extract ALL visible medical measurements and return ONLY this JSON object (no other text, no markdown, no code blocks):
{
  "client_id": "5-9 digit number visible in top area, or null",
  "client_name": "patient full name if visible, or null",
  "date": "date in DD.MM.YYYY format if visible, or null",
  "Gewicht_kg": number or null,
  "Grosse_cm": number or null,
  "BMI_kg_m2": number or null,
  "FM_kg": number or null,
  "FM_pct": number or null,
  "FMI_kg_m2": number or null,
  "FFM_kg": number or null,
  "FFM_pct": number or null,
  "FFMI_kg_m2": number or null,
  "SMM_kg": number or null,
  "R_ohm": number or null,
  "Xc_ohm": number or null,
  "VAT_l": number or null,
  "WC_cm": number or null,
  "phase_angle_deg": number or null,
  "perzentile": number or null,
  "TBW_l": number or null,
  "TBW_pct": number or null,
  "ECW_l": number or null,
  "ECW_pct": number or null,
  "ECW_TBW_pct": number or null
}`;

// Build OpenAI API request body
const requestBody = {
  model: "gpt-4o",
  max_tokens: 800,
  messages: [{
    role: "system",
    content: "You are a medical data extraction assistant. Extract data from hospital monitor screen photos. Always respond with valid JSON only. No explanations, no markdown, no code blocks. Just the raw JSON object."
  }, {
    role: "user",
    content: [
      {
        type: "image_url",
        image_url: {
          url: "data:" + mediaType + ";base64," + base64Image,
          detail: "high"
        }
      },
      {
        type: "text",
        text: PROMPT
      }
    ]
  }]
};

return [{ json: {
  requestBody,
  fileName: fileData.name,
  fileId: fileData.id,
  clientFolderId: prev.clientFolderId,
  clientFolderName: prev.clientFolderName,
  error: false
}}];

const staticData = this.getWorkflowStaticData('global');
if (!staticData.clients) staticData.clients = {};

const openaiResponse = $input.first().json;
const prev = $('Split Files').first().json;
const clientFolderName = prev.clientFolderName;

// Parse OpenAI response (different format from Anthropic)
let parsed;
try {
  let rawText = '';
  if (openaiResponse.choices && openaiResponse.choices[0]) {
    rawText = openaiResponse.choices[0].message.content.trim();
  }
  // Remove markdown wrappers if present
  const clean = rawText.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: {
    parseError: true,
    fileName: prev.fileName,
    fileId: prev.fileId,
    clientFolderId: prev.clientFolderId,
    clientFolderName: clientFolderName,
    rawResponse: openaiResponse.choices ? openaiResponse.choices[0].message.content : JSON.stringify(openaiResponse),
    errorMessage: e.message
  }}];
}

// Client ID from response or folder name
const clientId = (parsed.client_id && String(parsed.client_id).trim()) || clientFolderName;
const date = parsed.date || "unbekannt";

// Initialize client
if (!staticData.clients[clientId]) {
  staticData.clients[clientId] = {
    client_id: clientId,
    client_name: "",
    folderName: clientFolderName,
    operations: {}
  };
}

if (parsed.client_name && !staticData.clients[clientId].client_name) {
  staticData.clients[clientId].client_name = parsed.client_name;
}

if (!staticData.clients[clientId].operations[date]) {
  staticData.clients[clientId].operations[date] = {};
}

const FIELDS = [
  "Gewicht_kg","Grosse_cm","BMI_kg_m2",
  "FM_kg","FM_pct","FMI_kg_m2",
  "FFM_kg","FFM_pct","FFMI_kg_m2",
  "SMM_kg",
  "R_ohm","Xc_ohm",
  "VAT_l","WC_cm",
  "phase_angle_deg","perzentile",
  "TBW_l","TBW_pct","ECW_l","ECW_pct","ECW_TBW_pct"
];

const op = staticData.clients[clientId].operations[date];
for (const field of FIELDS) {
  if (parsed[field] !== null && parsed[field] !== undefined) {
    op[field] = parsed[field];
  }
}

return [{ json: {
  parseError: false,
  clientId,
  date,
  fileName: prev.fileName,
  fileId: prev.fileId,
  clientFolderId: prev.clientFolderId,
  clientFolderName: clientFolderName
}}];

const staticData = this.getWorkflowStaticData('global');
const prev = $('Split Clients').first().json;
const clientFolderName = prev.clientFolderName;
const config = prev.config || $('Set Config').first().json;

// Find client data - try folder name first
let clientData = staticData.clients[clientFolderName];
if (!clientData) {
  // Try to find by matching folderName
  for (const [id, data] of Object.entries(staticData.clients)) {
    if (data.folderName === clientFolderName) {
      clientData = data;
      break;
    }
  }
}

if (!clientData || Object.keys(clientData.operations).length === 0) {
  return [{ json: { skip: true, clientFolderName, clientFolderId: prev.clientFolderId } }];
}

// Sort dates chronologically
const sortedDates = Object.keys(clientData.operations)
  .filter(d => d !== "unbekannt")
  .sort((a, b) => {
    const parse = d => {
      const [dd, mm, yyyy] = d.split('.');
      return new Date(yyyy, mm - 1, dd);
    };
    return parse(a) - parse(b);
  });

if (clientData.operations["unbekannt"]) sortedDates.push("unbekannt");

const FIELD_ORDER = [
  "Gewicht_kg","Grosse_cm","BMI_kg_m2",
  "FM_kg","FM_pct","FMI_kg_m2",
  "FFM_kg","FFM_pct","FFMI_kg_m2",
  "SMM_kg",
  "R_ohm","Xc_ohm",
  "VAT_l","WC_cm",
  "phase_angle_deg","perzentile",
  "TBW_l","TBW_pct","ECW_l","ECW_pct","ECW_TBW_pct"
];

const operations = sortedDates.map((date, idx) => ({
  operationNumber: idx + 1,
  date,
  fields: clientData.operations[date]
}));

return [{ json: {
  skip: false,
  clientId: clientData.client_id,
  clientName: clientData.client_name || '',
  clientFolderName,
  clientFolderId: prev.clientFolderId,
  operations,
  fieldOrder: FIELD_ORDER,
  totalOps: operations.length,
  spreadsheetId: config.spreadsheetId,
  sheetGid: config.sheetGid,
  sheetName: config.sheetName
}}];

const sheetData = $input.first().json;
const prev = $('Has Sheet Data?').first().json;
const rows = sheetData.values || [];

const clientId = prev.clientId;
const clientName = prev.clientName;
const operations = prev.operations;
const FIELD_ORDER = prev.fieldOrder;
const sheetGid = prev.sheetGid;
const spreadsheetId = prev.spreadsheetId;
const sheetName = prev.sheetName;
const COLS_PER_OP = 21;
const START_COL = 2; // Column C (0-based)

// === Find existing max operation blocks in header (row 2, index 1) ===
const headerRow = rows[1] || [];
let maxOpBlock = 0;
headerRow.forEach(cell => {
  const match = cell && String(cell).match(/^(\d+)\.\s*Operation/);
  if (match) maxOpBlock = Math.max(maxOpBlock, parseInt(match[1]));
});

// === Find client row (column A, rows 6+, index 5+) ===
const clientRowMap = {};
for (let i = 5; i < rows.length; i += 2) {
  const id = rows[i] && rows[i][0];
  if (id) clientRowMap[String(id).trim()] = i + 1; // 1-based
}

const usedRows = Object.values(clientRowMap);
const nextFreeRow = usedRows.length > 0
  ? Math.max(...usedRows) + 2
  : 7; // Row 7 (first data row after headers 1-6)

let dateRow, dataRow;
if (clientRowMap[clientId]) {
  dateRow = clientRowMap[clientId];
  dataRow = clientRowMap[clientId] + 1;
} else {
  dateRow = nextFreeRow;
  dataRow = nextFreeRow + 1;
}

// === Build value ranges for batchUpdate ===
const valueRanges = [];

// --- Header rows for new operation blocks (rows 2-5) ---
const SECTION_HEADERS = ['BMI','BMI','BMI','Fettmasse','Fettmasse','Fettmasse','Fettfreie Masse','Fettfreie Masse','Fettfreie Masse','Skelettmuskelmasse','BIVA','BIVA','Viszerales Fett & Taillenumfang','Viszerales Fett & Taillenumfang','Phasenwinkel','Phasenwinkel','Wasser','Wasser','Wasser','Wasser','Wasser'];
const FIELD_NAMES = ['Gewicht','Größe','BMI','FM','FM','FMI','FFM','FFM','FFMI','SMM','R','Xc','VAT','Taillenumfang','φ','Perzentile','TBW','TBW','ECW','ECW','ECW/TBW'];
const UNITS = ['kg','cm','kg/m²','kg','%','kg/m²','kg','%','kg/m²','kg','Ω','Ω','l','cm','°','—','l','%','l','%','%'];

for (let opIdx = maxOpBlock; opIdx < operations.length; opIdx++) {
  const colStart = START_COL + opIdx * COLS_PER_OP;
  const colLetter = colToLetter(colStart);
  const colEndLetter = colToLetter(colStart + COLS_PER_OP - 1);

  // Row 2: "N. Operation"
  const row2 = new Array(COLS_PER_OP).fill('');
  row2[0] = (opIdx + 1) + '. Operation';
  valueRanges.push({
    range: sheetName + '!' + colLetter + '2:' + colEndLetter + '2',
    values: [row2]
  });

  // Row 3: Section headers
  valueRanges.push({
    range: sheetName + '!' + colLetter + '3:' + colEndLetter + '3',
    values: [SECTION_HEADERS]
  });

  // Row 4: Field names
  valueRanges.push({
    range: sheetName + '!' + colLetter + '4:' + colEndLetter + '4',
    values: [FIELD_NAMES]
  });

  // Row 5: Units
  valueRanges.push({
    range: sheetName + '!' + colLetter + '5:' + colEndLetter + '5',
    values: [UNITS]
  });
}

// --- Client data rows ---
// Date row: ID, Name, then dates in first cell of each op block
const maxCols = START_COL + Math.max(operations.length, maxOpBlock) * COLS_PER_OP;
const dateRowValues = new Array(maxCols).fill('');
dateRowValues[0] = clientId;
dateRowValues[1] = clientName;

// Data row: empty ID/Name, then values
const dataRowValues = new Array(maxCols).fill('');

operations.forEach((op, idx) => {
  const colOffset = START_COL + idx * COLS_PER_OP;
  dateRowValues[colOffset] = 'Datum der Operation: ' + op.date;

  FIELD_ORDER.forEach((field, fIdx) => {
    const val = op.fields[field];
    if (val !== undefined && val !== null) {
      dataRowValues[colOffset + fIdx] = val;
    }
  });
});

valueRanges.push({
  range: sheetName + '!A' + dateRow + ':' + colToLetter(maxCols - 1) + dateRow,
  values: [dateRowValues]
});
valueRanges.push({
  range: sheetName + '!A' + dataRow + ':' + colToLetter(maxCols - 1) + dataRow,
  values: [dataRowValues]
});

// === Build merge requests ===
const mergeRequests = [];

// Merge operation headers in row 2 for new blocks
for (let opIdx = maxOpBlock; opIdx < operations.length; opIdx++) {
  const colStart = START_COL + opIdx * COLS_PER_OP;
  mergeRequests.push({
    mergeCells: {
      range: {
        sheetId: sheetGid,
        startRowIndex: 1, endRowIndex: 2,
        startColumnIndex: colStart, endColumnIndex: colStart + COLS_PER_OP
      },
      mergeType: "MERGE_ALL"
    }
  });

  // Section merges in row 3
  const sectionSpans = [
    {name: 'BMI', start: 0, count: 3},
    {name: 'Fettmasse', start: 3, count: 3},
    {name: 'Fettfreie Masse', start: 6, count: 3},
    {name: 'Skelettmuskelmasse', start: 9, count: 1},
    {name: 'BIVA', start: 10, count: 2},
    {name: 'Viszerales Fett', start: 12, count: 2},
    {name: 'Phasenwinkel', start: 14, count: 2},
    {name: 'Wasser', start: 16, count: 5}
  ];

  sectionSpans.forEach(sec => {
    if (sec.count > 1) {
      mergeRequests.push({
        mergeCells: {
          range: {
            sheetId: sheetGid,
            startRowIndex: 2, endRowIndex: 3,
            startColumnIndex: colStart + sec.start,
            endColumnIndex: colStart + sec.start + sec.count
          },
          mergeType: "MERGE_ALL"
        }
      });
    }
  });
}

// Merge date cells for each operation in client's date row
operations.forEach((op, idx) => {
  const colStart = START_COL + idx * COLS_PER_OP;
  mergeRequests.push({
    mergeCells: {
      range: {
        sheetId: sheetGid,
        startRowIndex: dateRow - 1, endRowIndex: dateRow,
        startColumnIndex: colStart, endColumnIndex: colStart + COLS_PER_OP
      },
      mergeType: "MERGE_ALL"
    }
  });
});

// Helper: column index to letter
function colToLetter(col) {
  let letter = '';
  while (col >= 0) {
    letter = String.fromCharCode(65 + (col % 26)) + letter;
    col = Math.floor(col / 26) - 1;
  }
  return letter;
}

return [{ json: {
  spreadsheetId,
  sheetName,
  sheetGid,
  valueRanges,
  mergeRequests,
  clientFolderId: prev.clientFolderId,
  clientFolderName: prev.clientFolderName,
  clientId
}}];
